SELECT

FROM exam_sessions es
JOIN subjects s ON s.subject_id = es.subject_id
WHERE es.user_id = #{userId}
  AND es.exam_id = #{examId}

SELECT

FROM exam_sessions es
JOIN subjects s ON s.subject_id = es.subject_id
WHERE es.user_id = #{userId}
  AND es.subject_id = #{subjectId}
  AND es.status = 'GRADED'
ORDER BY es.graded_at DESC, es.exam_id DESC
LIMIT #{limit}
